import{_ as e,o as a,c as t,ae as n}from"./chunks/framework.Dzr56EFm.js";const c=JSON.parse('{"title":"设计趋势 - 2026-03-17","description":"","frontmatter":{"date":"2026-03-17T00:00:00.000Z","category":"UX Trend"},"headers":[],"relativePath":"daily/2026-03-17-uxtrend.md","filePath":"daily/2026-03-17-uxtrend.md"}'),o={name:"daily/2026-03-17-uxtrend.md"};function s(i,r,g,p,h,l){return a(),t("div",null,[...r[0]||(r[0]=[n('<h1 id="设计趋势-2026-03-17" tabindex="-1">设计趋势 - 2026-03-17 <a class="header-anchor" href="#设计趋势-2026-03-17" aria-label="Permalink to &quot;设计趋势 - 2026-03-17&quot;">​</a></h1><blockquote><p>AI交互方式、Prompt UX、Agent UX、Workflow</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日设计趋势聚焦于AI交互与工作流程优化。AI交互模式探索人机互动新方式，提升用户体验；AI工作流程设计模式结合AI与机器学习自动化任务执行。最值得关注的是AI界面设计的7个关键模式，以及产品设计师如何将AI融入设计工作流程，这些趋势预示着设计领域向智能化的进一步发展。</p><hr><h3 id="_1-ai交互模式-让用户识别并互动ai驱动功能" tabindex="-1">1. AI交互模式：让用户识别并互动AI驱动功能 <a class="header-anchor" href="#_1-ai交互模式-让用户识别并互动ai驱动功能" aria-label="Permalink to &quot;1. AI交互模式：让用户识别并互动AI驱动功能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@flik185/ai-interaction-patterns-giving-users-ways-to-recognize-and-interact-with-ai-driven-features-22055a91206b" target="_blank" rel="noreferrer">AI Interaction Patterns: Giving Users Ways to Recognize ... - Medium</a></p><p><strong>一句话摘要</strong>: 探索AI时代下人机交互新模式，提升用户体验。</p><p><strong>能解决什么问题</strong>: 如何让用户轻松识别并有效互动AI功能。</p><p><strong>产品应用</strong>: 适用于AI工具设计，如聊天机器人、分析仪表板等。</p><p><strong>示例场景</strong>: 在线客服聊天机器人明确告知用户正在与AI对话。</p><hr><h3 id="_2-代理型ai工作流程设计模式、示例及关注点" tabindex="-1">2. 代理型AI工作流程设计模式、示例及关注点 <a class="header-anchor" href="#_2-代理型ai工作流程设计模式、示例及关注点" aria-label="Permalink to &quot;2. 代理型AI工作流程设计模式、示例及关注点&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/codex/agentic-ai-workflows-design-patterns-examples-and-what-to-watch-in-2025-a3602b19b7e8" target="_blank" rel="noreferrer">Agentic AI Workflows Design Patterns, Examples, and what to watch ...</a></p><p><strong>一句话摘要</strong>: 代理型AI工作流程结合AI和ML自动化管理执行任务。</p><p><strong>能解决什么问题</strong>: 解决重复性工作，释放人力专注于高价值任务。</p><p><strong>产品应用</strong>: 适用于需要自动化、协作和适应性的实际产品。</p><p><strong>示例场景</strong>: 自动化物流系统，根据实时数据调整配送路线。</p><hr><h3 id="_3-ai代理工作流设计模式概览" tabindex="-1">3. AI代理工作流设计模式概览 <a class="header-anchor" href="#_3-ai代理工作流设计模式概览" aria-label="Permalink to &quot;3. AI代理工作流设计模式概览&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/binome/ai-agent-workflow-design-patterns-an-overview-cf9e1f609696" target="_blank" rel="noreferrer">AI Agent Workflow Design Patterns — An Overview | by Craig Li, Ph.D</a></p><p><strong>一句话摘要</strong>: 探讨AI代理工作流设计模式，分类为反思型和计划型。</p><p><strong>能解决什么问题</strong>: 如何设计AI代理以模拟人类推理，优化任务执行。</p><p><strong>产品应用</strong>: 可应用于AI代理框架，作为任务协调器处理不同问题。</p><p><strong>示例场景</strong>: 基于这些原则开发AI代理，用于灵活处理任务。</p><hr><h3 id="_4-ai界面设计的7个关键设计模式" tabindex="-1">4. AI界面设计的7个关键设计模式 <a class="header-anchor" href="#_4-ai界面设计的7个关键设计模式" aria-label="Permalink to &quot;4. AI界面设计的7个关键设计模式&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/ux-planet/7-key-design-patterns-for-ai-interfaces-893ab96988f6" target="_blank" rel="noreferrer">7 Key Design Patterns for AI Interfaces | by Fanny - UX Planet</a></p><p><strong>一句话摘要</strong>: 探索AI驱动产品界面设计的新兴模式。</p><p><strong>能解决什么问题</strong>: 解决AI系统在用户体验中的透明度、信任和灵活性问题。</p><p><strong>产品应用</strong>: 适用于需要AI辅助的产品设计，如聊天机器人、协作画布等。</p><p><strong>示例场景</strong>: 使用Figma AI进行智能编辑和协作。</p><hr><h3 id="_5-产品设计师如何将ai融入设计工作流程" tabindex="-1">5. 产品设计师如何将AI融入设计工作流程 <a class="header-anchor" href="#_5-产品设计师如何将ai融入设计工作流程" aria-label="Permalink to &quot;5. 产品设计师如何将AI融入设计工作流程&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@mariamargarida/ai-in-my-design-workflow-as-a-product-designer-feb120d8fe38" target="_blank" rel="noreferrer">AI In My Design Workflow As a Product Designer | by Maria Margarida</a></p><p><strong>一句话摘要</strong>: AI工具V0在快速原型设计和交互演示中的应用</p><p><strong>能解决什么问题</strong>: 解决复杂设计流程中的迭代和演示问题</p><p><strong>产品应用</strong>: 适用于需要快速迭代和演示交互的产品设计工作</p><p><strong>示例场景</strong>: 使用V0快速制作滚动行为和过渡效果的原型</p><hr><h3 id="_6-ai如何改变我的设计工作流程" tabindex="-1">6. AI如何改变我的设计工作流程 <a class="header-anchor" href="#_6-ai如何改变我的设计工作流程" aria-label="Permalink to &quot;6. AI如何改变我的设计工作流程&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@kazdenc/how-my-design-workflow-is-changing-with-ai-bc80e7fa3323" target="_blank" rel="noreferrer">How my design workflow is changing with AI | by Kazden Cattapan</a></p><p><strong>一句话摘要</strong>: AI技术加速设计流程，提高协作效率，减少猜测。</p><p><strong>能解决什么问题</strong>: 设计过程中的效率低下和协作困难。</p><p><strong>产品应用</strong>: 可以应用于产品设计，通过AI工具快速从研究到原型。</p><p><strong>示例场景</strong>: 使用AI工具快速迭代设计，减少开发周期。</p><hr><h3 id="_7-ai-ux指南-将功能转化为智能代理的框架" tabindex="-1">7. AI UX指南：将功能转化为智能代理的框架 <a class="header-anchor" href="#_7-ai-ux指南-将功能转化为智能代理的框架" aria-label="Permalink to &quot;7. AI UX指南：将功能转化为智能代理的框架&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/the-ai-ux-compass-a-framework-for-transforming-features-into-agents-f128dce92007" target="_blank" rel="noreferrer">The AI UX Compass: A framework for transforming features into agents</a></p><p><strong>一句话摘要</strong>: AI UX指南提供了一个框架，帮助设计师将传统功能转化为智能代理。</p><p><strong>能解决什么问题</strong>: 传统企业UX设计是交易性的，而智能代理需要系统主动与用户协作。</p><p><strong>产品应用</strong>: 适用于将现有企业软件功能转化为智能代理，提升用户体验。</p><p><strong>示例场景</strong>: 将报销报告功能转化为智能代理，自动处理报销流程。</p><hr><h3 id="_8-ai-ux-人工智能代理的体验设计" tabindex="-1">8. AI/UX：人工智能代理的体验设计 <a class="header-anchor" href="#_8-ai-ux-人工智能代理的体验设计" aria-label="Permalink to &quot;8. AI/UX：人工智能代理的体验设计&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/i-ux/ai-ux-experience-design-of-ai-agents-12e1051fa065" target="_blank" rel="noreferrer">AI/UX: Experience Design of AI Agents | by Noman Siddiqui - Medium</a></p><p><strong>一句话摘要</strong>: 用户体验设计从以人为中心转向包含智能代理。</p><p><strong>能解决什么问题</strong>: 解决如何为不需要传统界面元素的AI代理设计体验的问题。</p><p><strong>产品应用</strong>: 可以应用到个人助理、聊天机器人等，通过API和数据结构优化交互。</p><p><strong>示例场景</strong>: 智能代理自动安排会议，解读数据，协调沟通。</p><hr><h3 id="_9-代理型用户体验的崛起-用户体验的演变" tabindex="-1">9. 代理型用户体验的崛起：用户体验的演变 <a class="header-anchor" href="#_9-代理型用户体验的崛起-用户体验的演变" aria-label="Permalink to &quot;9. 代理型用户体验的崛起：用户体验的演变&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/the-rise-of-agentic-ux-why-user-experience-is-evolving-from-interaction-to-collaboration-945b06b31124" target="_blank" rel="noreferrer">The Rise of Agentic UX: Why User Experience Is Evolving ... - Medium</a></p><p><strong>一句话摘要</strong>: 用户体验正在从指导用户行为转变为减少或消除用户行为。</p><p><strong>能解决什么问题</strong>: 如何通过AI代理减少用户操作，提升用户体验。</p><p><strong>产品应用</strong>: 可以应用到智能助手、自动化服务等产品中，通过AI代理自动执行任务。</p><p><strong>示例场景</strong>: 智能健身助手自动规划并跟踪30天健身计划。</p><hr><h3 id="_10-以ai为先的设计工作流程重塑" tabindex="-1">10. 以AI为先的设计工作流程重塑 <a class="header-anchor" href="#_10-以ai为先的设计工作流程重塑" aria-label="Permalink to &quot;10. 以AI为先的设计工作流程重塑&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@desigink/reimagining-design-workflows-my-journey-into-ai-first-design-6ab11358dcae" target="_blank" rel="noreferrer">Reimagining design workflows: My journey into AI-first design</a></p><p><strong>一句话摘要</strong>: 利用AI提升设计工作流程的效率和质量</p><p><strong>能解决什么问题</strong>: 解决设计过程中数据收集和叙事构建的效率问题</p><p><strong>产品应用</strong>: 可以应用于产品设计，通过AI辅助分析和原型推荐提升效率</p><p><strong>示例场景</strong>: 使用GPT辅助设计Intercom的Messenger频道设置</p><hr>',75)])])}const f=e(o,[["render",s]]);export{c as __pageData,f as default};
